import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [mensagem, setMensagem] = useState('');
  const [periodos, setPeriodos] = useState([]);
  const [periodoId, setPeriodoId] = useState('');

  useEffect(() => {
    axios.get('/api/periodos').then(res => setPeriodos(res.data));
  }, []);

  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome);
      setRa(alunoEditando.ra);
      setPeriodoId(alunoEditando.periodo_id);
    } else {
      setNome('');
      setRa('');
      setPeriodoId('');
    }
  }, [alunoEditando]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (alunoEditando) {
      // Editando existente
      axios.put(`/api/alunos/${alunoEditando.id}`, { nome, ra, periodo_id: periodoId })
        .then(() => {
          setMensagem('Aluno atualizado!');
          setNome('');
          setRa('');
          setPeriodoId('');
          onNovoAluno();
          onFimEdicao();
        })
        .catch((err) => setMensagem('Erro ao atualizar aluno.'));
    } else {
      // Novo aluno
      axios.post('/api/alunos', { nome, ra, periodo_id: periodoId })
        .then(() => {
          setMensagem('Aluno cadastrado!');
          setNome('');
          setRa('');
          setPeriodoId('');
          onNovoAluno();
        })
        .catch((err) => setMensagem('Erro ao cadastrar aluno.'));
    }
  };

  return (
    <form onSubmit={handleSubmit} style={{ marginBottom: 24 }}>
      <h2>{alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}</h2>
      <div>
        <label>
          Nome:
          <input value={nome} onChange={e => setNome(e.target.value)} required />
        </label>
      </div>
      <div>
        <label>
          RA:
          <input value={ra} onChange={e => setRa(e.target.value)} required />
        </label>
      </div>
      <div>
        <label>Período</label>
        <select
          value={periodoId}
          onChange={e => setPeriodoId(e.target.value)}
        >
          <option value="">Selecione um período</option>
          {periodos.map(periodo => (
            <option key={periodo.id} value={periodo.id}>
              {periodo.nome}
            </option>
          ))}
        </select>
      </div>
      <button type="submit">{alunoEditando ? 'Atualizar' : 'Cadastrar'}</button>
      {alunoEditando && <button type="button" onClick={onFimEdicao}>Cancelar</button>}
      {mensagem && <p>{mensagem}</p>}
    </form>
  );
}

export default FormAluno;
